import boto3
import json
import time

def process_message(message_body):
    # Example processing based on message type
    if message_body.get('type') == 'email':
        send_email(message_body)
    elif message_body.get('type') == 'sms':
        send_sms(message_body)
    elif message_body.get('type') == 'database':
        update_database(message_body)
    else:
        print(f"Unknown message type: {message_body.get('type')}")

def send_email(message):
    print(f"Sending email: {message}")

def send_sms(message):
    print(f"Sending SMS: {message}")

def update_database(message):
    print(f"Updating database with: {message}")

def poll_sqs_queue(queue_url):
    sqs = boto3.client('sqs')
    while True:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )
        messages = response.get('Messages', [])
        for message in messages:
            message_body = json.loads(message['Body'])
            process_message(message_body)
            sqs.delete_message(
                QueueUrl=queue_url,
                ReceiptHandle=message['ReceiptHandle']
            )
        time.sleep(1)

if __name__ == "__main__":
    queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/MyQueue'
    poll_sqs_queue(queue_url)